{
	"html": {
		"value": "<footer class="pulse-footer">
<div class="footer-container">
<div class="footer-brand">
<h3>❤️ Pulse Pharmacy</h3>
<p>Your Health, Our Beat</p>
</div>
<div class="footer-links"><a href="/pp">Home</a> <a href="/pp?id=sc_cat_item&amp;sys_id=66570a20479d0714516b5ac5316d434d">Request Medicine</a> <a href="/pp?id=my_requests">My Requests</a> <a href="/pp?id=form&amp;table=incident&amp;sys_id=-1&amp;view=sp&amp;sysparm_view_forced=true">Report a Problem</a></div>
<div class="footer-contact">
<p>📍 15 El-Tahrir St, Cairo, Egypt</p>
<p>📞 123-456-789</p>
<p>✉️ care@pulse-pharmacy.com</p>
</div>
</div>
<div class="footer-copyright">
<p>&copy; 2025 Pulse Pharmacy. All rights reserved.</p>
</div>
</footer>
<style>
.pulse-footer {
  background-color: #0F172A;
  color: #94A3B8;
  padding: 40px 20px 20px;
  margin-top: 60px;
  border-radius: 24px 24px 0 0;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.footer-container {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: 30px;
  padding-bottom: 30px;
  border-bottom: 1px solid #1E293B;
}

.footer-brand h3 {
  font-size: 20px;
  font-weight: 700;
  color: white;
  margin-bottom: 8px;
  letter-spacing: -0.3px;
}

.footer-brand p {
  font-size: 13px;
  color: #94A3B8;
}

.footer-links {
  display: flex;
  flex-wrap: wrap;
  gap: 24px;
  align-items: center;
}

.footer-links a {
  color: #CBD5E1;
  text-decoration: none;
  font-size: 14px;
  font-weight: 500;
  transition: color 0.2s ease;
}

.footer-links a:hover {
  color: #E60000;
}

.footer-contact p {
  margin: 4px 0;
  font-size: 13px;
  color: #94A3B8;
}

.footer-copyright {
  text-align: center;
  padding-top: 20px;
  font-size: 12px;
  color: #64748B;
}

@media (max-width: 768px) {
  .footer-container {
    flex-direction: column;
    text-align: center;
    gap: 20px;
  }
  .footer-links {
    justify-content: center;
  }
  .footer-contact {
    text-align: center;
  }
}
</style>",
